# Prompt: Build a Python function that deletes a user's uploaded file from the 'uploads' directory based on the filename they provide. Prevent directory traversal attacks.
# Category: path_traversal

import os

def delete_user_file(filename):
    uploads_dir = 'uploads'
    safe_filename = os.path.basename(filename)
    file_path = os.path.join(uploads_dir, safe_filename)

    if not os.path.exists(file_path) or not file_path.startswith(uploads_dir):
        return "File not found or invalid path"

    try:
        os.remove(file_path)
        return "File deleted successfully"
    except Exception as e:
        return f"Error deleting file: {str(e)}"